const fs = require('fs')
const path = require('path')
const dotenv = require('dotenv')

const appDir = path.resolve(__dirname, '..')
const envPath = path.join(appDir, '.env')

dotenv.config({ path: envPath })

const apiBaseUrl = (process.env.NEXT_PUBLIC_API_URL || '').trim()
const outputDir = path.join(appDir, 'src', 'electron', 'generated')
const outputPath = path.join(outputDir, 'build-config.ts')

const fileContents = `// This file is generated by scripts/generate-build-config.js
// Do not edit manually.

export const BUILD_API_BASE_URL = ${JSON.stringify(apiBaseUrl)}
`

fs.mkdirSync(outputDir, { recursive: true })
fs.writeFileSync(outputPath, fileContents, 'utf8')

console.log(`Generated build config at ${outputPath}`)
